import * as fs from 'node:fs';
import * as path from 'node:path';
import { Spectrum } from './src/spectrum.ts';

const CACHE_DIR = path.join\('test', '.cache'\);
const h8 = \(v: number\) => v.toString\(16\).toUpperCase\(\).padStart\(2, '0'\);

async function fetchROM\(model: string\) {
  const urls: Record<string, string> = {
    '128k': 'https://raw.githubusercontent.com/spectrumforeveryone/zx-roms/main/spectrum128-plus2/128/spec128uk.rom',
  };
  const url = urls[model];
  const filename = url.split\('/'\).pop\(\)!;
  const cachePath = path.join\(CACHE_DIR, filename\);
  if \(fs.existsSync\(cachePath\)\) return new Uint8Array\(fs.readFileSync\(cachePath\)\);
  const resp = await fetch\(url\);
  const data = new Uint8Array\(await resp.arrayBuffer\(\)\);
  fs.mkdirSync\(CACHE_DIR, { recursive: true }\);
  fs.writeFileSync\(cachePath, data\);
  return data;
}

async function main\(\) {
  const tapPath = 'C:\\\\Users\\\\damie\\\\Desktop\\\\Buzzsaw+\(FoxtonLocksMix\).TAP';
  const tapData = new Uint8Array\(fs.readFileSync\(tapPath\)\);
  console.log\('TAP loaded, size=' + tapData.length\);

  const spec = new Spectrum\('128k'\);
  console.log\('Spectrum created'\);
  spec.loadROM\(await fetchROM\('128k'\)\);
  console.log\('ROM loaded'\);
  spec.reset\(\);
  console.log\('Reset done'\);
  spec.loadTAP\(tapData\);
  console.log\('TAP set'\);
  spec.tape.rewind\(\);
  spec.tape.paused = false;
  spec.tape.startPlayback\(\);
  console.log\('Tape started'\);

  // Boot and load
  console.log\('Ticking 100...'\);
  for \(let i = 0; i < 100; i++\) spec.tick\(\);
  console.log\('Done 100 ticks'\);
  spec.keyboard.handleKeyEvent\('Enter', true\);
  for \(let i = 0; i < 5; i++\) spec.tick\(\);
  spec.keyboard.handleKeyEvent\('Enter', false\);
  console.log\('Enter pressed'\);
  for \(let i = 0; i < 200; i++\) spec.tick\(\);
  console.log\('Done 200 ticks'\);
  spec.keyboard.handleKeyEvent\('Space', true\);
  console.log\('Ticking 5000...'\);
  for \(let i = 0; i < 5000; i++\) spec.tick\(\);
  console.log\('Done 5000 ticks'\);
  spec.keyboard.handleKeyEvent\('Space', false\);
  console.log\('Ticking 3000...'\);
  for \(let i = 0; i < 3000; i++\) spec.tick\(\);
  console.log\('Done 3000 ticks'\);

  // Check what's at the detection addresses
  console.log\('Memory at detection addresses:'\);
  console.log\('  [0B52] = ' + h8\(spec.cpu.memory[0x0B52]\) + ' \(expected D6 for 128K/+2\)'\);
  console.log\('  [0B53] = ' + h8\(spec.cpu.memory[0x0B53]\) + ' \(expected 9F for +2A/+3\)'\);

  // Check ROM raw bytes
  const romData = await fetchROM\('128k'\);
  console.log\('\\nROM 0 \(128K editor\) bytes:'\);
  console.log\('  ROM0[0B52] = ' + h8\(romData[0x0B52]\)\);
  console.log\('  ROM0[0B53] = ' + h8\(romData[0x0B53]\)\);
  console.log\('\\nROM 1 \(48K BASIC\) bytes:'\);
  console.log\('  ROM1[0B52] = ' + h8\(romData[0x4000 + 0x0B52]\)\);
  console.log\('  ROM1[0B53] = ' + h8\(romData[0x4000 + 0x0B53]\)\);

  // Check what ROM is paged in
  console.log\('\\nECEC \(mode var\) = ' + h8\(spec.cpu.memory[0xECEC]\)\);

  // Dump 0B50-0B60 from memory as-seen
  console.log\('\\nMemory 0B50-0B60:'\);
  const bytes: string[] = [];
  for \(let i = 0x0B50; i < 0x0B60; i++\) bytes.push\(h8\(spec.cpu.memory[i]\)\);
  console.log\('  ' + bytes.join\(' '\)\);

  // Check port 7FFD state
  console.log\('\\nLast port 7FFD value: ' + h8\(\(spec as any\).last7FFD || 0\)\);
}

main\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
